nodejs/exercise_middleware1.htm.solution:
function authenticate(req, res, next) {
  const token = req.header('authorization');
  if (!token) {
    return res.status(401).json({ message: 'Unauthorized' });
  }
  req.user = { id: 123, name: 'User' };
  next();
}

