nodejs/exercise_promises1.htm.solution:
function createDelayedPromise(ms) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      resolve('Resolved after ' + ms + ' milliseconds');
    }, ms);
  });
}

